"""Evaluation metrics for BioASQ factoid QA: SAcc, LAcc, MRR."""


def strict_accuracy(pred, golds):
    """Exact match (case-insensitive)."""
    pred_lower = pred.strip().lower()
    return int(any(pred_lower == g.strip().lower() for g in golds))


def lenient_accuracy(pred, golds):
    """Substring match (case-insensitive)."""
    pred_lower = pred.strip().lower()
    for g in golds:
        g_lower = g.strip().lower()
        if pred_lower in g_lower or g_lower in pred_lower:
            return 1
    return 0


def mean_reciprocal_rank(pred_list, golds):
    """MRR given a ranked list of predictions."""
    golds_lower = [g.strip().lower() for g in golds]
    for i, p in enumerate(pred_list):
        p_lower = p.strip().lower()
        if any(p_lower == g or p_lower in g or g in p_lower for g in golds_lower):
            return 1.0 / (i + 1)
    return 0.0


def compute_metrics(predictions, gold_answers_list):
    """
    Compute aggregate SAcc, LAcc, MRR.

    Args:
        predictions: list of predicted answer strings (or list of lists for MRR)
        gold_answers_list: list of lists of gold answer strings
    Returns:
        dict with sacc, lacc, mrr
    """
    n = len(predictions)
    if n == 0:
        return {"sacc": 0.0, "lacc": 0.0, "mrr": 0.0}

    sacc_sum = 0
    lacc_sum = 0
    mrr_sum = 0

    for i in range(n):
        pred = predictions[i]
        golds = gold_answers_list[i]

        if not golds:
            continue

        if isinstance(pred, list):
            # pred is a ranked list
            sacc_sum += strict_accuracy(pred[0] if pred else "", golds)
            lacc_sum += lenient_accuracy(pred[0] if pred else "", golds)
            mrr_sum += mean_reciprocal_rank(pred, golds)
        else:
            # pred is a single string
            sacc_sum += strict_accuracy(pred, golds)
            lacc_sum += lenient_accuracy(pred, golds)
            # For MRR with a single prediction, reciprocal rank is 1 if correct, 0 otherwise
            mrr_sum += mean_reciprocal_rank([pred], golds)

    return {
        "sacc": 100.0 * sacc_sum / n,
        "lacc": 100.0 * lacc_sum / n,
        "mrr": 100.0 * mrr_sum / n,
    }

